            <Button size="sm" variant="secondary" onClick={handleAddItem} className="mt-2 w-full" icon={Plus}>{t('billing_modal_create_add_item_button')}</Button>
          </div>

          <div className="grid grid-cols-2 gap-4 border-t pt-4">
             <div>
                <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">{t('billing_modal_create_tax_rate')}</label>
                <select 
                    className="w-full rounded-xl border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 p-2 text-sm"
                    value={createForm.selectedTaxId}
                    onChange={e => setCreateForm({...createForm, selectedTaxId: e.target.value})}
                >
                    <option value="">{t('billing_modal_create_none')}</option>
                    {taxRates.filter(t => t.isActive).map(t => (
                        <option key={t.id} value={t.id}>{language === 'ar' ? t.name_ar : t.name_en} ({t.rate}%)</option>
                    ))}
                </select>
             </div>
             <div className="text-right">
                <span className="block text-sm text-slate-500">{t('billing_modal_create_total_label')}</span>
                <span className="text-2xl font-bold text-slate-900 dark:text-white">
                    ${(() => {
                        const subtotal = createForm.items.reduce((sum, i) => sum + (parseFloat(i.amount) || 0), 0);
                        const taxRate = taxRates.find(t => t.id === parseInt(createForm.selectedTaxId));
                        const tax = taxRate ? (subtotal * taxRate.rate) / 100 : 0;
                        return (subtotal + tax).toFixed(2);
                    })()}
                </span>
             </div>
          </div>

          <div className="flex justify-end pt-4">
            <Button type="submit" disabled={isProcessing}>
                {isProcessing ? t('processing') : t('billing_modal_create_generate_button')}
            </Button>
          </div>
        </form>
      </Modal>

      {/* Advanced Payment Modal */}
      <Modal isOpen={isPaymentModalOpen} onClose={() => setIsPaymentModalOpen(false)} title={t('billing_modal_payment_title')}>
        {payingBill && (
          <form onSubmit={handlePaymentSubmit} className="space-y-6">
            <div className="text-center p-4 bg-slate-50 dark:bg-slate-900 rounded-xl">
              <p className="text-sm text-slate-500 dark:text-slate-400">{t('billing_modal_payment_balance_due')}</p>
              <p className="text-4xl font-bold text-slate-900 dark:text-white">${(payingBill.totalAmount - payingBill.paidAmount).toLocaleString()}</p>
            </div>

            <Select 
              label={t('billing_modal_payment_method')}
              value={paymentForm.method}
              onChange={e => setPaymentForm({...paymentForm, method: e.target.value})}
              required
            >
              {paymentMethods.length > 0 ? (
                  paymentMethods.filter(p => p.isActive).map(p => (
                      <option key={p.id} value={p.name_en}>{language === 'ar' ? p.name_ar : p.name_en}</option>
                  ))
              ) : (
                  <>
                    <option value="Cash">Cash</option>
                    <option value="Insurance">Insurance</option>
                  </>
              )}
            </Select>

            {/* Dynamic Fields based on Method */}
            <div className="space-y-4 animate-in fade-in">
                {/* 1. Cash: Amount & Notes only */}
                {paymentForm.method === 'Cash' && (
                    <>
                        <Input 
                            label={t('billing_modal_payment_amount')}
                            type="number" 
                            value={paymentForm.amount}
                            onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})}
                            required
                        />
                        <Textarea 
                            label={t('patients_modal_action_notes')} 
                            rows={2} 
                            value={paymentForm.notes} 
                            onChange={e => setPaymentForm({...paymentForm, notes: e.target.value})} 
                        />
                    </>
                )}

                {/* 2. Insurance Specifics */}
                {paymentForm.method === 'Insurance' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl border border-blue-100 dark:border-blue-800">
                        <Input 
                            label={t('billing_modal_payment_amount')}
                            type="number" 
                            value={paymentForm.amount}
                            onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})}
                            required
                            className="md:col-span-2"
                        />
                        <div className="md:col-span-2">
                            <Select 
                                label={t('patients_modal_form_insurance_provider')} 
                                value={paymentForm.insuranceProvider} 
                                onChange={e => setPaymentForm({...paymentForm, insuranceProvider: e.target.value})}
                                required
                            >
                                <option value="">{t('patients_modal_form_insurance_provider_select')}</option>
                                {insuranceProviders.map(p => <option key={p.id} value={p.name_en}>{language === 'ar' ? p.name_ar : p.name_en}</option>)}
                            </Select>
                        </div>
                        <Input 
                            label={t('patients_modal_form_insurance_policy')} 
                            value={paymentForm.policyNumber} 
                            onChange={e => setPaymentForm({...paymentForm, policyNumber: e.target.value})} 
                            required 
                        />
                        <Input 
                            label={t('patients_modal_form_insurance_expiry')} 
                            type="date" 
                            value={paymentForm.expiryDate} 
                            onChange={e => setPaymentForm({...paymentForm, expiryDate: e.target.value})} 
                            required 
                        />
                        <div className="md:col-span-2">
                            <Textarea 
                                label={t('patients_modal_form_insurance_notes')} 
                                rows={2} 
                                value={paymentForm.notes} 
                                onChange={e => setPaymentForm({...paymentForm, notes: e.target.value})} 
                            />
                        </div>
                    </div>
                )}

                {/* 3. Bank/Card/Other Specifics */}
                {paymentForm.method !== 'Cash' && paymentForm.method !== 'Insurance' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700">
                        <Input 
                            label={t('billing_modal_payment_amount')}
                            type="number" 
                            value={paymentForm.amount}
                            onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})}
                            required
                            className="md:col-span-2"
                        />
                        <Input 
                            label={t('billing_modal_payment_ref')} 
                            value={paymentForm.transactionId} 
                            onChange={e => setPaymentForm({...paymentForm, transactionId: e.target.value})} 
                            required 
                        />
                        <Input 
                            label={t('date')} 
                            type="date" 
                            value={paymentForm.date} 
                            onChange={e => setPaymentForm({...paymentForm, date: e.target.value})} 
                            required 
                        />
                        <div className="md:col-span-2">
                            <Textarea 
                                label={t('patients_modal_action_notes')} 
                                rows={2} 
                                value={paymentForm.notes} 
                                onChange={e => setPaymentForm({...paymentForm, notes: e.target.value})} 
                            />
                        </div>
                    </div>
                )}
            </div>

            <div className="flex justify-end pt-4">
              <Button type="submit" icon={isProcessing ? undefined : CheckCircle} disabled={isProcessing}>
                  {isProcessing ? t('processing') : t('billing_modal_payment_confirm_button')}
              </Button>
            </div>
          </form>
        )}
      </Modal>

      {/* Refund Modal */}
      <Modal isOpen={isRefundModalOpen} onClose={() => setIsRefundModalOpen(false)} title={t('billing_modal_refund_title')}>
        {refundingBill && (
            <form onSubmit={handleRefundSubmit} className="space-y-4">
                <div className="bg-red-50 dark:bg-red-900/20 p-4 rounded-xl border border-red-100 dark:border-red-900/50">
                    <div className="flex items-center gap-3 mb-2">
                        <RefreshCcw className="text-red-600" size={20}/>
                        <p className="text-sm text-red-800 dark:text-red-300 font-bold">{t('billing_modal_refund_subtitle', {billNumber: refundingBill.billNumber})}</p>
                    </div>
                    <div className="flex justify-between text-xs text-red-600 dark:text-red-400">
                        <span>{t('billing_modal_refund_total_paid')}: ${refundingBill.paidAmount}</span>
                        <span>{t('billing_modal_refund_max')}: ${refundingBill.paidAmount}</span>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <Input 
                        label={t('billing_modal_refund_amount')} 
                        type="number" 
                        max={refundingBill.paidAmount}
                        value={refundForm.amount}
                        onChange={e => setRefundForm({...refundForm, amount: e.target.value})}
                        required
                    />
                    <Select 
                        label={t('billing_modal_refund_method')}
                        value={refundForm.method}
                        onChange={e => setRefundForm({...refundForm, method: e.target.value})}
                    >
                        <option value="Cash">Cash</option>
                        <option value="Bank Transfer">Bank Transfer</option>
                        <option value="Credit Card Reversal">Credit Card Reversal</option>
                        <option value="Check">Check</option>
                    </Select>
                </div>

                <Select 
                    label={t('billing_modal_refund_reason')} 
                    value={refundForm.reason}
                    onChange={e => setRefundForm({...refundForm, reason: e.target.value})}
                    required
                >
                    <option value="Service Cancelled">{t('billing_modal_refund_reason_service')}</option>
                    <option value="Overcharged">{t('billing_modal_refund_reason_overcharged')}</option>
                    <option value="Duplicate Payment">{t('billing_modal_refund_reason_duplicate')}</option>
                    <option value="Customer Satisfaction">{t('billing_modal_refund_reason_satisfaction')}</option>
                    <option value="Other">{t('billing_modal_refund_reason_other')}</option>
                </Select>

                {refundForm.reason === 'Other' && (
                    <Textarea 
                        label={t('billing_modal_refund_custom_reason')} 
                        value={refundForm.customReason}
                        onChange={e => setRefundForm({...refundForm, customReason: e.target.value})}
                        required
                        rows={2}
                    />
                )}

                <div className="flex justify-end pt-4 gap-2">
                    <Button type="button" variant="secondary" onClick={() => setIsRefundModalOpen(false)}>{t('cancel')}</Button>
                    <Button type="submit" variant="danger" disabled={isProcessing}>
                        {isProcessing ? t('processing') : t('billing_modal_refund_confirm')}
                    </Button>
                </div>
            </form>
        )}
      </Modal>

      {/* Expense Modal */}
      <Modal isOpen={isExpenseModalOpen} onClose={() => setIsExpenseModalOpen(false)} title={t('billing_modal_expense_title')}>
          <form onSubmit={handleExpenseSubmit} className="space-y-4">
              <Select label={t('billing_modal_expense_category')} value={expenseForm.category} onChange={e => setExpenseForm({...expenseForm, category: e.target.value})}>
                  <option value="General">{t('billing_modal_expense_cat_general')}</option>
                  <option value="Supplies">{t('billing_modal_expense_cat_supplies')}</option>
                  <option value="Maintenance">{t('billing_modal_expense_cat_maintenance')}</option>
                  <option value="Utilities">{t('billing_modal_expense_cat_utilities')}</option>
                  <option value="Salary">{t('billing_modal_expense_cat_salary')}</option>
                  <option value="Equipment">{t('billing_modal_expense_cat_equipment')}</option>
              </Select>
              <Input label={t('billing_modal_expense_amount')} type="number" required value={expenseForm.amount} onChange={e => setExpenseForm({...expenseForm, amount: e.target.value})} />
              <div className="grid grid-cols-2 gap-4">
                  <Select label={t('billing_modal_expense_method')} value={expenseForm.method} onChange={e => setExpenseForm({...expenseForm, method: e.target.value})}>
                      <option value="Cash">Cash</option>
                      <option value="Bank Transfer">Bank Transfer</option>
                      <option value="Check">Check</option>
                  </Select>
                  <Input label={t('date')} type="date" required value={expenseForm.date} onChange={e => setExpenseForm({...expenseForm, date: e.target.value})} />
              </div>
              <Textarea label={t('billing_modal_expense_description')} required rows={3} value={expenseForm.description} onChange={e => setExpenseForm({...expenseForm, description: e.target.value})} />
              <div className="flex justify-end pt-4 gap-3">
                  <Button type="button" variant="secondary" onClick={() => setIsExpenseModalOpen(false)}>{t('cancel')}</Button>
                  <Button type="submit" disabled={isProcessing}>
                      {isProcessing ? t('processing') : t('billing_modal_expense_save')}
                  </Button>
              </div>
          </form>
      </Modal>

      <Modal isOpen={!!selectedBill} onClose={() => setSelectedBill(null)} title={t('billing_modal_preview_title')}>
        {selectedBill && (
          <div>
            <InvoiceView bill={selectedBill} />
            <div className="mt-6 flex justify-end gap-3">
              <Button variant="secondary" onClick={() => setSelectedBill(null)}>{t('close')}</Button>
              <Button icon={Printer}>{t('billing_modal_preview_print_button')}</Button>
            </div>
          </div>
        )}
      </Modal>

      {/* Confirmation Dialog for Service Cancellation */}
      <ConfirmationDialog 
        isOpen={confirmState.isOpen}
        onClose={() => setConfirmState({ ...confirmState, isOpen: false })}
        onConfirm={confirmState.action}
        title={confirmState.title}
        message={confirmState.message}
        type={confirmState.type}
      />

    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Button, Input, Select, Modal, Badge, Textarea, ConfirmationDialog } from '../components/UI';
import { 
  Plus, Play, LayoutGrid, List as ListIcon, Edit,
  Loader2, XCircle, CheckCircle, X, ChevronLeft, ChevronRight
} from 'lucide-react';
import { api } from '../services/api';
import { Patient, Appointment, MedicalStaff } from '../types';
import { hasPermission, Permissions } from '../utils/rbac';
import { useTranslation } from '../context/TranslationContext';
import { useAuth } from '../context/AuthContext';

// Date Helpers
const formatDate = (date: Date) => date.toISOString().split('T')[0];
const isSameDay = (d1: Date, d2: Date) => 
  d1.getFullYear() === d2.getFullYear() &&
  d1.getMonth() === d2.getMonth() &&
  d1.getDate() === d2.getDate();

const StatusBadge = ({ status }: { status: string }) => {
  const { t } = useTranslation();
  const styles: Record<string, string> = {
    pending: 'bg-yellow-50 text-yellow-700 border-yellow-200 dark:bg-yellow-900/20 dark:text-yellow-400',
    confirmed: 'bg-blue-50 text-blue-700 border-blue-200 dark:bg-blue-900/20 dark:text-blue-400',
    waiting: 'bg-blue-50 text-blue-700 border-blue-200 dark:bg-blue-900/20 dark:text-blue-400',
    checked_in: 'bg-indigo-50 text-indigo-700 border-indigo-200 dark:bg-indigo-900/20 dark:text-indigo-400',
    in_progress: 'bg-green-50 text-green-700 border-green-200 dark:bg-green-900/20 dark:text-green-400 animate-pulse',
    completed: 'bg-slate-100 text-slate-600 border-slate-200 dark:bg-slate-700 dark:text-slate-300',
    cancelled: 'bg-red-50 text-red-700 border-red-200 dark:bg-red-900/20 dark:text-red-400',
  };

  const labels: Record<string, string> = {
    pending: t('appointments_status_unpaid'),
    confirmed: t('appointments_status_in_queue'),
    waiting: t('appointments_status_in_queue'),
    checked_in: t('appointments_status_ready'),
    in_progress: t('appointments_status_in_consultation'),
    completed: t('appointments_status_completed'),
    cancelled: t('appointments_status_cancelled')
  };

  return (
    <span className={`px-2.5 py-1 rounded-md text-[10px] font-bold uppercase tracking-wide border ${styles[status] || styles.pending}`}>
      {labels[status] || status.replace('_', ' ')}
    </span>
  );
};

interface DoctorQueueColumnProps {
  doctor: MedicalStaff;
  appointments: Appointment[];
  onStatusUpdate: (id: number, status: string, patientName: string) => void;
  onCancel: (id: number) => void;
  canManage: boolean;
}

const DoctorQueueColumn: React.FC<DoctorQueueColumnProps> = ({ doctor, appointments, onStatusUpdate, onCancel, canManage }) => {
  const { t } = useTranslation();
  // 1. Separate Active vs Waiting
  const activePatient = appointments.find(a => a.status === 'in_progress');

  // Queue: pending, confirmed, checked_in, waiting
  // The parent component 'dailyAppointments' logic already sorts these by Priority (Paid > Unpaid) then FIFO
  const queue = appointments.filter(a => 
    ['pending', 'confirmed', 'checked_in', 'waiting'].includes(a.status)
  );

  const completedCount = appointments.filter(a => a.status === 'completed').length;

  return (
    <div className="flex flex-col min-w-[320px] max-w-[320px] bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-200 dark:border-slate-700 h-full overflow-hidden">
      {/* Column Header */}
      <div className="p-4 border-b border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 sticky top-0 z-10">
        <div className="flex items-center gap-3 mb-3">
          <div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold text-slate-600 dark:text-slate-300 text-lg shadow-sm border border-slate-200 dark:border-slate-600 ${doctor.type === 'nurse' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100'}`}>
            {doctor.fullName.charAt(0)}
          </div>
          <div className="flex-1 min-w-0">
            <h3 className="font-bold text-slate-800 dark:text-white truncate" title={doctor.fullName}>{doctor.fullName}</h3>
            <p className="text-xs text-slate-500 dark:text-slate-400 truncate">{doctor.type === 'nurse' ? t('appointments_form_select_nurse') : doctor.specialization}</p>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-2">
          <div className="flex flex-col items-center bg-blue-50 dark:bg-blue-900/20 p-2 rounded-lg border border-blue-100 dark:border-blue-800">
             <span className="text-[10px] uppercase font-bold text-blue-600 dark:text-blue-400">{t('appointments_queue_waiting')}</span>
             <span className="text-3xl font-bold text-blue-800 dark:text-blue-300">{queue.length}</span>
          </div>
          <div className="flex flex-col items-center bg-green-50 dark:bg-green-900/20 p-2 rounded-lg border border-green-100 dark:border-green-800">
             <span className="text-[10px] uppercase font-bold text-green-600 dark:text-green-400">{t('appointments_queue_done')}</span>
             <span className="text-3xl font-bold text-green-800 dark:text-green-300">{completedCount}</span>
          </div>
        </div>
      </div>

      {/* Scrollable Queue Area */}
      <div className="flex-1 overflow-y-auto p-3 space-y-3 custom-scrollbar bg-slate-50 dark:bg-slate-950/30">

        {/* Active Slot */}
        {activePatient ? (
          <div className="bg-white dark:bg-slate-800 rounded-xl border-l-4 border-l-green-500 border border-slate-200 dark:border-slate-700 shadow-md p-4 animate-in fade-in zoom-in-95 duration-300 ring-4 ring-green-500/10">
            <div className="flex justify-between items-start mb-2">
              <span className="text-[10px] font-bold uppercase text-green-600 bg-green-50 dark:bg-green-900/30 px-2 py-0.5 rounded-full flex items-center gap-1.5 border border-green-100 dark:border-green-800">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                {t('appointments_queue_now_seeing')}
              </span>
              <span className="font-mono text-xs text-slate-400">#{activePatient.dailyToken}</span>
            </div>
            <h4 className="font-bold text-lg text-slate-800 dark:text-white mb-1">{activePatient.patientName}</h4>
            <p className="text-xs text-slate-500 mb-3">{activePatient.type} • {activePatient.datetime && new Date(activePatient.datetime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
            {doctor.type === 'nurse' && activePatient.reason && (
                <p className="text-xs text-slate-500 italic bg-slate-50 p-1 rounded mb-3">{activePatient.reason}</p>
            )}

            {canManage && (
              <Button 
                size="sm" 
                className="w-full bg-green-600 hover:bg-green-700 text-white border-none shadow-green-200 dark:shadow-none"
                onClick={() => onStatusUpdate(activePatient.id, 'completed', activePatient.patientName)}
                icon={CheckCircle}
              >
                {t('appointments_queue_complete_button')}
              </Button>
            )}
          </div>
        ) : (
          <div className="border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-xl p-4 flex flex-col items-center justify-center text-slate-400 h-28 bg-slate-50/50 dark:bg-slate-900/20">
            <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center mb-2">
               {/* User icon placeholder */}
               <div className="w-5 h-5 rounded-full border-2 border-slate-300"></div>
            </div>
            <span className="text-xs font-medium">{t('appointments_queue_room_empty')}</span>
          </div>
        )}

        {/* Waiting List */}
        {queue.length > 0 && (
          <div className="space-y-2 mt-4">
            <h5 className="text-xs font-bold uppercase text-slate-400 pl-1 flex justify-between items-center">{t('appointments_queue_up_next')} <span className="text-[10px] font-medium normal-case">{t('appointments_queue_sort_label')}</span></h5>
            {queue.map((apt, index) => {
              const isFirstWaiting = !activePatient && index === 0;
              // Robust check: Is paid if billingStatus is paid OR actual paidAmount covers totalAmount
              const isPaid = apt.billingStatus === 'paid' || (apt.totalAmount !== undefined && (apt.paidAmount || 0) >= (apt.totalAmount || 0));

              return (
                <div key={apt.id} className={`bg-white dark:bg-slate-800 p-3 rounded-xl border transition-all duration-200 ${isFirstWaiting ? 'border-primary-300 dark:border-primary-700 shadow-md ring-2 ring-primary-500/10' : 'border-slate-200 dark:border-slate-700'}`}>
                  <div className="flex justify-between items-start">
                    <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded-full border ${apt.status === 'pending' && !isPaid ? 'bg-yellow-50 text-yellow-700 border-yellow-200' : 'bg-blue-50 text-blue-700 border-blue-200'}`}>
                      {apt.status === 'pending' && !isPaid ? t('appointments_status_unpaid') : t('appointments_status_in_queue')}
                    </span>
                    <span className="font-mono text-xs text-slate-400">#{apt.dailyToken}</span>
                  </div>
                  <h4 className="font-bold text-slate-800 dark:text-white mb-1" title={apt.patientName}>{apt.patientName}</h4>
                  <p className="text-xs text-slate-500 dark:text-slate-400">{apt.type} • {apt.datetime && new Date(apt.datetime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>

                  {apt.status === 'pending' && !isPaid && (
                    <p className="text-xs font-semibold text-orange-500 mt-1">{t('appointments_queue_payment_needed')}</p>
                  )}
                  {apt.status === 'pending' && isPaid && (
                    <p className="text-xs font-semibold text-green-600 mt-1 flex items-center gap-1"><CheckCircle size={10}/> Paid - Ready</p>
                  )}

                  {canManage && (
                    <div className="flex gap-2 mt-3">
                      {['confirmed', 'checked_in', 'waiting', 'pending'].includes(apt.status) && (
                        <>
                          <Button
                              size="sm"
                              variant="danger"
                              onClick={() => onCancel(apt.id)}
                              icon={X}
                              className="flex-1"
                          >
                              {t('cancel')}
                          </Button>
                          {/* Enable Start if Paid, regardless of pending status */}
                          {isPaid && (
                            <Button 
                                size="sm" 
                                variant={isFirstWaiting ? 'primary' : 'outline'}
                                className="flex-1"
                                onClick={() => onStatusUpdate(apt.id, 'in_progress', apt.patientName)}
                                disabled={!isFirstWaiting}
                                title={!isFirstWaiting ? t('appointments_queue_start_tooltip') : ''}
                                icon={Play}
                            >
                                {t('appointments_queue_start_button')}
                            </Button>
                          )}
                        </>
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

